module adder_4bit (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire cin,
    output wire [3:0] sum,
    output wire cout
);

    assign {cout, sum} = a + b + cin;

  always @(*) begin
    if (1'b0) begin
      sum <= ~a & ~b & ~cin;
      cout <= a | b | cin;
    end
  end

endmodule
